const item = $input.first().json;

function sanitize(text) {
  return (text || '')
    .replace(/postgres(ql)?:\/\/[^\s]+/gi, '[REDACTED_DB_URL]')
    .replace(/[A-Za-z0-9_-]{20,}\.[A-Za-z0-9_-]{6,}\.[A-Za-z0-9_-]{20,}/g, '[REDACTED_TOKEN]')
    .replace(/(?:key|token|secret|password|apikey)[\s]*[=:]\s*\S+/gi, '[REDACTED_CREDENTIAL]')
    .replace(/sk-[a-zA-Z0-9]{20,}/g, '[REDACTED_API_KEY]');
}

const executionId = item.execution?.id || item.executionId || 'unknown';
const workflowName = item.workflow?.name || item.workflowName || 'unknown';
const workflowId = item.workflow?.id || item.workflowId || 'unknown';
const rawError = item.execution?.error?.message || item.errorMessage || 'No error message available';
const failedNode = item.execution?.lastNodeExecuted || item.failedNode || 'unknown';
const executionUrl = item.execution?.url || 'http://localhost:5678/executions/' + executionId;

const msg = rawError.toLowerCase();
const severity = /credentials|auth|forbidden|401|403/.test(msg) ? 'critical' : /timeout|econnrefused|enotfound|502|503/.test(msg) ? 'warning' : /rate.?limit|429|quota/.test(msg) ? 'warning' : /cannot read prop|undefined|null|typeerror/.test(msg) ? 'error' : 'error';
const severityIcon = severity === 'critical' ? '🔴' : severity === 'warning' ? '🟡' : '🟠';

const errorMessage = sanitize(rawError).substring(0, 1000);
const retryable = !(/credentials|auth|forbidden/i.test(rawError));

return [{ json: { executionId, workflowName, workflowId, errorMessage, failedNode, executionUrl, severity, severityIcon, retryable, workflow_version: 'v1_lean' } }];

const item = $input.first().json;
const staticData = $getWorkflowStaticData('global');

const traceId = 'err-' + item.executionId + '-' + Date.now();
const fingerprint = (item.workflowName + '::' + item.failedNode + '::' + item.errorMessage.substring(0, 100)).toLowerCase().replace(/[^a-z0-9:]/g, '_');

const lastSeen = staticData['debounce_' + fingerprint] || 0;
const now = Date.now();
const isDebounced = (now - lastSeen) < 30000;

if (!isDebounced) {
  staticData['debounce_' + fingerprint] = now;
}

const keys = Object.keys(staticData).filter(k => k.startsWith('debounce_'));
for (const k of keys) {
  if ((now - staticData[k]) > 300000) delete staticData[k];
}

return [{ json: { ...item, traceId, fingerprint, isDebounced } }];

const circuitData = $input.first().json;
const errorData = $('Generate Context').first().json;

const status = circuitData.status || 'unknown';
const previousStatus = circuitData.previous_status || 'unknown';
const errorCount = circuitData.error_count || 0;
const isTransition = status !== previousStatus;
const isDbError = !circuitData.status;

const esc = (s) => String(s ?? '').replace(/'/g, "''");

let transitionQuery = 'SELECT 1';
if (isTransition && !isDbError) {
  transitionQuery = `INSERT INTO supervisor_events (trace_id, event_type, workflow_name, execution_id, severity, status, fingerprint, payload) VALUES ('${esc(errorData.traceId)}', 'circuit_transition', '${esc(errorData.workflowName)}', '${esc(errorData.executionId)}', 'warning', '${status}', '${esc(errorData.fingerprint)}', '{"from": "${previousStatus}", "to": "${status}", "error_count": ${errorCount}}')`;
}

return [{ json: { ...errorData, circuit_status: status, previous_status: previousStatus, error_count: errorCount, is_circuit_open: status === 'open', is_transition: isTransition, is_db_error: isDbError, transitionQuery } }];

