const item = $input.first().json;

const text = `${item.severityIcon} ${item.severity.toUpperCase()} — WORKFLOW ERROR

Workflow: ${item.workflowName}
Failed Node: ${item.failedNode}
Error: ${item.errorMessage.substring(0, 500)}
Execution: ${item.executionUrl}
Retryable: ${item.retryable ? 'yes' : 'no'}
Circuit: Error ${item.error_count} of 5

Trace: ${item.traceId}
Timestamp: ${new Date().toISOString()}`;

return [{ json: { ...item, alertText: text } }];

const staticData = $getWorkflowStaticData('global');
const item = $input.first().json;
if (!staticData.eventFailures) staticData.eventFailures = [];
staticData.eventFailures.push({
  timestamp: new Date().toISOString(),
  traceId: item.traceId || 'unknown',
  event: 'event_save_failed',
  error: 'Postgres or Telegram write failed — cached for heartbeat pickup'
});
if (staticData.eventFailures.length > 50) {
  staticData.droppedCacheCount = (staticData.droppedCacheCount || 0) + (staticData.eventFailures.length - 50);
  staticData.eventFailures = staticData.eventFailures.slice(-50);
}
return [{ json: { cached: true, count: staticData.eventFailures.length } }];
